def _sha256_bytes(b: bytes) -> str:
    return hashlib.sha256(b).hexdigest()


def _softmax(x: np.ndarray) -> np.ndarray:
    x = x.astype(np.float64)
    x = x - np.max(x)
    ex = np.exp(x)
    s = ex / np.sum(ex)
    return s


def _ensure_dir(path: str) -> None:
    os.makedirs(path, exist_ok=True)


def _read_image_bytes(upload: UploadFile) -> bytes:
    data = upload.file.read()
    if data is None:
        raise HTTPException(status_code=400, detail="No file data received")
    if len(data) > MAX_IMAGE_BYTES:
        raise HTTPException(status_code=413, detail=f"Image too large (>{MAX_IMAGE_BYTES} bytes)")
    return data


def _load_image_from_bytes(image_bytes: bytes) -> np.ndarray:
    buf = io.BytesIO(image_bytes)
    try:
        img = face_recognition.load_image_file(buf)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image file")
    return img


def _extract_encodings(
    img: np.ndarray,
    face_model: str = DEFAULT_FACE_MODEL,
    upsample: int = DEFAULT_UPSAMPLE,
    num_jitters: int = DEFAULT_NUM_JITTERS,
) -> Tuple[List[np.ndarray], List[Tuple[int, int, int, int]]]:
    try:
        locations = face_recognition.face_locations(img, number_of_times_to_upsample=upsample, model=face_model)
        if len(locations) > MAX_FACES_PER_IMAGE:
            locations = locations[:MAX_FACES_PER_IMAGE]
        encodings = face_recognition.face_encodings(img, known_face_locations=locations, num_jitters=num_jitters)
        encodings = [np.asarray(e, dtype=np.float32) for e in encodings]
        return encodings, locations
    except HTTPException:
        raise
    except Exception:
        raise HTTPException(status_code=500, detail="Failed to detect/encode faces")


def _list_dataset(dataset_dir: str) -> List[Tuple[str, str]]:
    items = []
    if not os.path.isdir(dataset_dir):
        return items
    for person in sorted(os.listdir(dataset_dir)):
        person_dir = os.path.join(dataset_dir, person)
        if not os.path.isdir(person_dir):
            continue
        for fn in sorted(os.listdir(person_dir)):
            if fn.lower().endswith((".jpg", ".jpeg", ".png", ".bmp")):
                items.append((person, os.path.join(person_dir, fn)))
    return items


def _train_from_dataset(
    dataset_dir: str,
    face_model: str = DEFAULT_FACE_MODEL,
    upsample: int = DEFAULT_UPSAMPLE,
    num_jitters: int = DEFAULT_NUM_JITTERS,
) -> Dict[str, Any]:
    pairs = _list_dataset(dataset_dir)
    if not pairs:
        raise HTTPException(status_code=400, detail=f"No training images found in {dataset_dir}")

    X = []
    y = []
    per_class_counts: Dict[str, int] = {}
    skipped: List[Dict[str, Any]] = []

    for label, path in pairs:
        try:
            img = face_recognition.load_image_file(path)
            encs, locs = _extract_encodings(img, face_model=face_model, upsample=upsample, num_jitters=num_jitters)
            if len(encs) == 0:
                skipped.append({"label": label, "path": path, "reason": "no_face_detected"})
                continue
            if len(encs) > 1:
                skipped.append({"label": label, "path": path, "reason": "multiple_faces_detected", "faces": len(encs)})
                continue
            X.append(encs[0])
            y.append(label)
            per_class_counts[label] = per_class_counts.get(label, 0) + 1
        except Exception as e:
            skipped.append({"label": label, "path": path, "reason": "error", "error": str(e)})

    if len(X) < 2:
        raise HTTPException(status_code=400, detail="Not enough usable training samples")

    labels = sorted(set(y))
    if len(labels) < 2:
        raise HTTPException(status_code=400, detail="Need at least 2 distinct classes to train")

    X_arr = np.vstack([x.reshape(1, -1) for x in X]).astype(np.float32)
    y_arr = np.array(y)

    clf = SVC(
        C=DEFAULT_SVC_C,
        kernel="rbf",
        gamma=DEFAULT_SVC_GAMMA,
        probability=DEFAULT_SVC_PROBABILITY,
        class_weight="balanced",
        random_state=42,
    )
    clf.fit(X_arr, y_arr)

    meta = {
        "trained_at": int(time.time()),
        "dataset_dir": os.path.abspath(dataset_dir),
        "face_model": face_model,
        "upsample": upsample,
        "num_jitters": num_jitters,
        "n_samples": int(len(X_arr)),
        "n_classes": int(len(labels)),
        "classes": list(clf.classes_),
        "per_class_counts": per_class_counts,
        "skipped": skipped,
        "svc": {"C": DEFAULT_SVC_C, "gamma": DEFAULT_SVC_GAMMA, "kernel": "rbf", "probability": True},
    }

    return {"model": clf, "metadata": meta}


def _save_artifacts(model: Any, metadata: Dict[str, Any], model_path: str, labels_path: str, metadata_path: str) -> None:
    _ensure_dir(os.path.dirname(model_path))
    joblib.dump(model, model_path)
    with open(labels_path, "w", encoding="utf-8") as f:
        json.dump({"classes": metadata.get("classes", [])}, f, ensure_ascii=False, indent=2)
    with open(metadata_path, "w", encoding="utf-8") as f:
        json.dump(metadata, f, ensure_ascii=False, indent=2)


def _load_artifacts(model_path: str, metadata_path: str) -> Tuple[Any, Dict[str, Any]]:
    if not os.path.isfile(model_path) or not os.path.isfile(metadata_path):
        raise FileNotFoundError("Model artifacts not found")
    model = joblib.load(model_path)
    with open(metadata_path, "r", encoding="utf-8") as f:
        meta = json.load(f)
    return model, meta


def _require_key(x_api_key: Optional[str]) -> None:
    if not REQUIRE_API_KEY:
        return
    if not API_KEY:
        raise HTTPException(status_code=500, detail="Server misconfigured: REQUIRE_API_KEY enabled but API_KEY not set")
    if not x_api_key or x_api_key != API_KEY:
        raise HTTPException(status_code=401, detail="Unauthorized")


class TrainRequest(BaseModel):
    dataset_dir: str = Field(default=DEFAULT_DATASET_DIR)
