app = FastAPI(title=APP_NAME, version="1.0.0")

STATE = {
    "model": None,
    "metadata": None,
    "model_path": DEFAULT_MODEL_PATH,
    "metadata_path": DEFAULT_METADATA_PATH,
}


@app.on_event("startup")
def _startup() -> None:
    try:
        model, meta = _load_artifacts(DEFAULT_MODEL_PATH, DEFAULT_METADATA_PATH)
        STATE["model"] = model
        STATE["metadata"] = meta
        STATE["model_path"] = DEFAULT_MODEL_PATH
        STATE["metadata_path"] = DEFAULT_METADATA_PATH
        logger.info("Loaded model from %s", DEFAULT_MODEL_PATH)
    except Exception:
        logger.info("No model loaded on startup")


@app.get("/health")
def health() -> Dict[str, Any]:
    return {
        "ok": True,
        "model_loaded": STATE["model"] is not None,
        "model_path": STATE["model_path"],
        "metadata_path": STATE["metadata_path"],
    }


@app.post("/train")
def train(
    req: TrainRequest = Body(...),
    x_api_key: Optional[str] = Query(default=None, alias="x_api_key"),
) -> Dict[str, Any]:
    _require_key(x_api_key)

    result = _train_from_dataset(
        dataset_dir=req.dataset_dir,
        face_model=req.face_model,
        upsample=req.upsample,
        num_jitters=req.num_jitters,
    )
    model = result["model"]
    meta = result["metadata"]

    _save_artifacts(model, meta, req.model_path, req.labels_path, req.metadata_path)

    STATE["model"] = model
    STATE["metadata"] = meta
    STATE["model_path"] = req.model_path
    STATE["metadata_path"] = req.metadata_path

    return {"ok": True, "saved": True, "model_path": req.model_path, "metadata_path": req.metadata_path, "metadata": meta}


@app.post("/reload")
def reload_model(
    model_path: str = Body(default=DEFAULT_MODEL_PATH),
    metadata_path: str = Body(default=DEFAULT_METADATA_PATH),
    x_api_key: Optional[str] = Query(default=None, alias="x_api_key"),
) -> Dict[str, Any]:
    _require_key(x_api_key)
    try:
        model, meta = _load_artifacts(model_path, metadata_path)
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Failed to load artifacts: {e}")
    STATE["model"] = model
    STATE["metadata"] = meta
    STATE["model_path"] = model_path
    STATE["metadata_path"] = metadata_path
    return {"ok": True, "model_loaded": True, "model_path": model_path, "metadata_path": metadata_path, "metadata": meta}


@app.post("/predict", response_model=PredictResponse)
def predict(
    file: UploadFile = File(...),
    face_model: str = Query(default=DEFAULT_FACE_MODEL),
    upsample: int = Query(default=DEFAULT_UPSAMPLE, ge=0, le=3),
    num_jitters: int = Query(default=1, ge=1, le=10),
    include_bbox: bool = Query(default=True),
    include_raw_scores: bool = Query(default=True),
    x_api_key: Optional[str] = Query(default=None, alias="x_api_key"),
) -> Any:
    _require_key(x_api_key)

    model = STATE["model"]
    meta = STATE["metadata"]
    if model is None or meta is None:
        raise HTTPException(status_code=400, detail="Model not loaded. Train or reload first.")

    image_bytes = _read_image_bytes(file)
    request_id = _sha256_bytes(image_bytes)[:16]
    img = _load_image_from_bytes(image_bytes)

    encs, locs = _extract_encodings(img, face_model=face_model, upsample=upsample, num_jitters=num_jitters)
    classes = list(getattr(model, "classes_", []))

    faces_out: List[Dict[str, Any]] = []
    if len(encs) == 0:
        return {
            "request_id": request_id,
            "model_loaded": True,
            "n_faces": 0,
            "faces": [],
            "classes": classes,
            "metadata": meta,
        }

    X = np.vstack([e.reshape(1, -1) for e in encs]).astype(np.float32)

    proba = None
    raw_scores = None

    if hasattr(model, "predict_proba"):
        proba = model.predict_proba(X)
        proba = np.asarray(proba, dtype=np.float64)
    if include_raw_scores and hasattr(model, "decision_function"):
        try:
            raw_scores = model.decision_function(X)
            raw_scores = np.asarray(raw_scores, dtype=np.float64)
            if raw_scores.ndim == 1:
                raw_scores = raw_scores.reshape(-1, 1)
        except Exception:
            raw_scores = None

    for i in range(X.shape[0]):
        face_entry: Dict[str, Any] = {"face_index": i}

        if include_bbox:
            top, right, bottom, left = locs[i]
            face_entry["bbox"] = {"top": int(top), "right": int(right), "bottom": int(bottom), "left": int(left)}

        if proba is not None:
            p = proba[i]
            p = p / max(1e-12, float(np.sum(p)))
            dist = {classes[j]: float(p[j]) for j in range(len(classes))}
            pred_idx = int(np.argmax(p))
            face_entry["predicted_class"] = classes[pred_idx] if classes else None
            face_entry["confidence"] = float(p[pred_idx]) if classes else None
            face_entry["probabilities"] = dist
        else:
            if raw_scores is None:
                raise HTTPException(status_code=500, detail="Model does not support probability output")
            s = raw_scores[i]
            if len(classes) == 2 and s.shape[0] == 1:
                s = np.array([-s[0], s[0]], dtype=np.float64)
            p = _softmax(s)
            dist = {classes[j]: float(p[j]) for j in range(len(classes))}
            pred_idx = int(np.argmax(p))
            face_entry["predicted_class"] = classes[pred_idx] if classes else None
            face_entry["confidence"] = float(p[pred_idx]) if classes else None
            face_entry["probabilities"] = dist

        if include_raw_scores and raw_scores is not None:
            face_entry["raw_scores"] = {classes[j]: float(raw_scores[i][j]) for j in range(min(len(classes), raw_scores.shape[1]))}

        faces_out.append(face_entry)

    return {
        "request_id": request_id,
        "model_loaded": True,
        "n_faces": len(faces_out),
        "faces": faces_out,
        "classes": classes,
        "metadata": meta,
    }


